// --- Utilities ---
function gid() { return Date.now().toString(36) + Math.random().toString(36).substr(2, 9); }
function fDate(iso) { if (!iso) return "N/A"; return new Date(iso).toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric", hour: "2-digit", minute: "2-digit" }); }
function sDate(iso) { if (!iso) return ""; const d = (Date.now() - new Date(iso).getTime()) / 1000; if (d < 60) return "just now"; if (d < 3600) return Math.floor(d / 60) + "m"; if (d < 86400) return Math.floor(d / 3600) + "h"; if (d < 604800) return Math.floor(d / 86400) + "d"; return new Date(iso).toLocaleDateString("en-US", { month: "short", day: "numeric" }); }
function daysBetween(a, b) { return Math.abs(Math.floor((new Date(a).getTime() - new Date(b).getTime()) / 86400000)); }
function daysSince(iso) { return Math.floor((Date.now() - new Date(iso).getTime()) / 86400000); }

function seededRandom(seed) { let h = 0xdeadbeef ^ seed; return function () { h = Math.imul(h ^ (h >>> 16), 2246822507); h = Math.imul(h ^ (h >>> 13), 3266489909); return ((h ^= h >>> 16) >>> 0) / 4294967296; }; }

async function hashPw(pw, salt) { const d = new TextEncoder().encode(salt + ":" + pw); const buf = await crypto.subtle.digest("SHA-256", d); return Array.from(new Uint8Array(buf)).map(b => b.toString(16).padStart(2, "0")).join(""); }
function genSalt() { const a = new Uint8Array(16); crypto.getRandomValues(a); return Array.from(a).map(b => b.toString(16).padStart(2, "0")).join(""); }
function genToken() { const a = new Uint8Array(32); crypto.getRandomValues(a); return Array.from(a).map(b => b.toString(16).padStart(2, "0")).join(""); }
function valPw(pw) { if (pw.length < 8) return "Min 8 characters."; if (!/[A-Z]/.test(pw)) return "Need uppercase."; if (!/[a-z]/.test(pw)) return "Need lowercase."; if (!/[0-9]/.test(pw)) return "Need number."; return null; }

// ── Registration validation helpers ──
const RESERVED_USERNAMES = new Set(["admin", "administrator", "system", "moderator", "mod", "trustassembly", "support", "help", "root", "null", "undefined", "anonymous", "bot", "official", "staff", "team", "security", "abuse", "info", "contact", "webmaster", "postmaster"]);
const DISPOSABLE_EMAIL_DOMAINS = new Set(["mailinator.com", "guerrillamail.com", "tempmail.com", "throwaway.email", "yopmail.com", "sharklasers.com", "guerrillamailblock.com", "grr.la", "guerrillamail.info", "guerrillamail.net", "trashmail.com", "trashmail.me", "trashmail.net", "10minutemail.com", "temp-mail.org", "fakeinbox.com", "maildrop.cc", "dispostable.com", "mailnesia.com", "getairmail.com", "mohmal.com", "burnermail.io"]);

function sanitizeUsername(raw) {
  // Strip ALL whitespace including zero-width chars, leading @, then lowercase
  return raw.replace(/[\s\u200B\u200C\u200D\uFEFF\u00A0]/g, "").replace(/^@+/, "").toLowerCase();
}

function valUsername(uname) {
  if (uname.length < 3) return "Username: 3 character minimum.";
  if (uname.length > 30) return "Username: 30 character maximum.";
  if (!/^[a-z0-9_]+$/.test(uname)) return "Username: letters, numbers, and underscores only.";
  if (/^_|_$/.test(uname)) return "Username can't start or end with underscore.";
  if (/__/.test(uname)) return "Username can't have consecutive underscores.";
  if (RESERVED_USERNAMES.has(uname)) return "That username is reserved.";
  return null;
}

function valEmail(raw) {
  const email = raw.trim().toLowerCase();
  if (!email) return "Email required.";
  // RFC-lite: something@something.something
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/.test(email)) return "Enter a valid email address.";
  const domain = email.split("@")[1];
  if (DISPOSABLE_EMAIL_DOMAINS.has(domain)) return "Disposable email addresses are not allowed.";
  return null;
}

function normalizeEmail(raw) {
  let email = raw.trim().toLowerCase();
  const [local, domain] = email.split("@");
  // Gmail dot normalization: a.b.c@gmail.com → abc@gmail.com
  if (domain === "gmail.com" || domain === "googlemail.com") {
    // Also strip +aliases: user+tag@gmail.com → user@gmail.com
    const base = local.split("+")[0].replace(/\./g, "");
    email = base + "@gmail.com";
  }
  return email;
}

function valDisplayName(name) {
  if (!name.trim()) return "Display name required.";
  if (name.trim().length > 50) return "Display name: 50 character maximum.";
  return null;
}

function valRealName(name) {
  if (!name.trim()) return "Legal name required.";
  if (name.trim().length > 80) return "Legal name: 80 character maximum.";
  return null;
}

const MAX_SIGNUPS_PER_IP_PER_HOUR = 3;
async function checkSignupRate(ipHash) {
  const key = `ta-rate-${ipHash}`;
  const existing = (await sG(key)) || [];
  const oneHourAgo = Date.now() - 3600000;
  const recent = existing.filter(t => t > oneHourAgo);
  if (recent.length >= MAX_SIGNUPS_PER_IP_PER_HOUR) return "Too many signups from this connection. Please try again later.";
  recent.push(Date.now());
  await sS(key, recent);
  return null;
}

function hotScore(sub) {
  const cg = sub.crossGroupVotes ? Object.values(sub.crossGroupVotes).filter(v => v.approve).length : 0;
  const ig = sub.votes ? Object.values(sub.votes).filter(v => v.approve).length : 0;
  const s = cg * 3 + ig;
  const order = Math.log10(Math.max(Math.abs(s), 1));
  const sign = s > 0 ? 1 : s < 0 ? -1 : 0;
  const epoch = new Date("2025-01-01").getTime() / 1000;
  const sec = new Date(sub.createdAt).getTime() / 1000 - epoch;
  return sign * order + sec / 45000;
}

// --- Storage (API-backed via PostgreSQL) ---
async function sG(k) {
  // Throws on failure so callers using (await sG(SK.X)) || {} don't
  // mistake a network/auth error for "no data" and overwrite real data.
  const res = await fetch("/api/kv?key=" + encodeURIComponent(k));
  if (!res.ok) throw new Error(`Storage read failed for ${k}: ${res.status}`);
  const data = await res.json();
  return data.value ? JSON.parse(data.value) : null;
}
async function sS(k, v) {
  try {
    const res = await fetch("/api/kv", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ key: k, value: JSON.stringify(v) }),
    });
    return res.ok;
  } catch { return false; }
}

async function ensureGeneralPublic() {
  // sG throws on read failure, so this will never mistake an error for "no data"
  let gpId = await sG(SK.GP);
  if (gpId) return gpId;
  const orgs = (await sG(SK.ORGS)) || {};
  // Check if it already exists
  for (const [id, o] of Object.entries(orgs)) { if (o.name === GP_NAME) { await sS(SK.GP, id); return id; } }
  // Create it
  const id = gid();
  orgs[id] = { id, name: GP_NAME, description: GP_DESC, charter: "Open to all. Permanent membership. Cannot be left.", createdBy: "system", createdAt: new Date().toISOString(), members: [], isGeneralPublic: true };
  await sS(SK.ORGS, orgs); await sS(SK.GP, id);
  return id;
}

// ============================================================
// JURY SELECTION ENGINE
// ============================================================
// Jury size scales with assembly membership:
// - 5–20 members:    3 jurors (simple majority: 2/3)
// - 21–50 members:   5 jurors (simple majority: 3/5)
// - 51–100 members:  7 jurors (simple majority: 4/7)
// - 101–999 members: 9 jurors (simple majority: 5/9)
// - 1,000–9,999:     11 jurors (simple majority: 6/11)
// - 10,000+:         13 jurors (simple majority: 7/13)
//
// Additional rules activate at thresholds:
// - 100 members: no repeat reviewer of same submitter, demographic diversity attempted
// - 500 members: jurors can't have joined within 30 days of each other
// - 1000 members: 24h cooldown deprioritization
// - Cross-group consensus requires 5+ assemblies with 100+ members

function getJurySize(memberCount) {
  if (memberCount >= 10000) return 13;
  if (memberCount >= 1000) return 11;
  if (memberCount >= 101) return 9;
  if (memberCount >= 51) return 7;
  if (memberCount >= 21) return 5;
  return 3;
}

// Super jury: ~2× regular, always odd, minimum 7
function getSuperJurySize(memberCount) {
  if (memberCount >= 10000) return 17;
  if (memberCount >= 1000) return 15;
  if (memberCount >= 101) return 13;
  if (memberCount >= 51) return 11;
  if (memberCount >= 21) return 9;
  return 7;
}

