// ── Scoring Weights (★ = community-votable in future elections) ──
const W = {
  win: 1.0,              // ★ points per approved correction
  disputeWin: 2.0,       // ★ points per successful dispute
  streakInterval: 3,     // ★ consecutive wins per bonus point
  qualityDivisor: 10,    // ★ quality normalization: (news+fun)/X
  qualityCap: 1.6,       // ★ soft cap on quality multiplier (prevents inflation beyond ~8+8)
  qualityExp: 1.5,       // ★ exponent on quality (amplifies gap between trivial and important)
  lossDrag: 2.0,         // ★ loss severity coefficient (inside √)
  lieDrag: 3.0,          // ★ lie severity per lie (linear, no mercy)
  failedDisputeDrag: 2.0,// ★ failed dispute severity (inside √)
  vindicationBase: 10.0, // ★ base value of Cassandra vindication
  persistenceExp: 1.5,   // ★ exponent on rejection count for vindication
};
const CROSS_GROUP_DECEPTION_MULT = 9; // Assembly-level deception penalty

// ── Cross-Group Jury System ──
const CROSS_GROUP_QUALIFYING_SIZE = 100; // Assembly must have 100+ members for cross-group eligibility
const CROSS_GROUP_MIN_ASSEMBLIES = 5;    // Minimum qualifying assemblies before activation
const MAX_SHARED_ASSEMBLIES = 2;         // Max non-GP assemblies any two jurors can share

function getCrossGroupJurySize(qualifyingAssemblyCount) {
  if (qualifyingAssemblyCount >= 100) return 13;
  if (qualifyingAssemblyCount >= 51) return 11;
  if (qualifyingAssemblyCount >= 21) return 9;
  if (qualifyingAssemblyCount >= 13) return 7;
  if (qualifyingAssemblyCount >= 8) return 5;
  return 3; // 5-7 qualifying assemblies
}

// Count non-GP assembly memberships shared between two users
function sharedNonGPMemberships(userA, userB, gpOrgId) {
  const aOrgs = (userA.orgIds || []).filter(id => id !== gpOrgId);
  const bOrgs = new Set((userB.orgIds || []).filter(id => id !== gpOrgId));
  return aOrgs.filter(id => bOrgs.has(id)).length;
}

async function selectCrossGroupJury(orgId, submitterUsername) {
  const orgs = (await sG(SK.ORGS)) || {};
  const users = (await sG(SK.USERS)) || {};
  const gpOrgId = await sG(SK.GP);

  // Find qualifying assemblies (100+ members, not the originating one)
  const qualifyingOrgs = Object.entries(orgs).filter(([oid, o]) =>
    oid !== orgId && !o.isGeneralPublic && o.members.length >= CROSS_GROUP_QUALIFYING_SIZE
  );
  const qualifyingCount = qualifyingOrgs.length;
  const rulesApplied = [];

  if (qualifyingCount < CROSS_GROUP_MIN_ASSEMBLIES) {
    return { jurors: [], seed: 0, rulesApplied: [`Insufficient qualifying assemblies (${qualifyingCount}/${CROSS_GROUP_MIN_ASSEMBLIES})`], jurySize: 0, qualifyingCount, error: `Cross-group requires ${CROSS_GROUP_MIN_ASSEMBLIES}+ assemblies with ${CROSS_GROUP_QUALIFYING_SIZE}+ members. Currently: ${qualifyingCount}.` };
  }

  const jurySize = getCrossGroupJurySize(qualifyingCount);
  rulesApplied.push(`${qualifyingCount} qualifying assemblies → ${jurySize}-person jury`);

  // Build pool: all members of qualifying assemblies who are NOT in the originating assembly
  const originMembers = new Set(orgs[orgId]?.members || []);
  const poolSet = new Set();
  for (const [, o] of qualifyingOrgs) {
    for (const m of o.members) {
      if (m !== submitterUsername && !originMembers.has(m)) poolSet.add(m);
    }
  }
  let pool = [...poolSet];

  if (pool.length < jurySize) {
    return { jurors: [], seed: 0, rulesApplied: [...rulesApplied, "Insufficient non-overlapping jurors"], jurySize, qualifyingCount, error: "Not enough eligible jurors outside originating assembly." };
  }

  // Seed and shuffle
  const seed = Date.now() + Math.floor(Math.random() * 10000);
  const rng = seededRandom(seed);
  const shuffled = [...pool].sort(() => rng() - 0.5);

  // Greedy selection with overlap constraint
  const selected = [];
  const selectedUsers = [];
  rulesApplied.push(`Overlap constraint: ≤${MAX_SHARED_ASSEMBLIES} shared non-GP assemblies per pair`);

  for (const candidate of shuffled) {
    if (selected.length >= jurySize) break;
    const cu = users[candidate];
    if (!cu) continue;

    // Check overlap with every already-selected juror
    const passesOverlap = selectedUsers.every(su =>
      sharedNonGPMemberships(cu, su, gpOrgId) <= MAX_SHARED_ASSEMBLIES
    );

    if (passesOverlap) {
      selected.push(candidate);
      selectedUsers.push(cu);
    }
  }

  // If we couldn't fill the jury with the overlap constraint, fall back to largest possible
  if (selected.length < 3) {
    return { jurors: [], seed, rulesApplied: [...rulesApplied, "Could not seat minimum 3 jurors with overlap constraint"], jurySize, qualifyingCount, error: "Insufficient diverse jurors (overlap constraint too restrictive for current population)." };
  }

  if (selected.length < jurySize) {
    rulesApplied.push(`Reduced jury: ${selected.length}/${jurySize} (overlap constraint limited pool)`);
  }

  return { jurors: selected, seed, rulesApplied, jurySize: selected.length, qualifyingCount, error: null };
}

// ── Concession Time Decay ──
// Returns fraction of reputation recoverable based on time since cross-group rejection
function getConcessionRecovery(rejectedAt, concessionsThisWeek = 0) {
  const hours = (Date.now() - new Date(rejectedAt).getTime()) / 3600000;
  if (hours <= 168) {  // within 1 week
    return concessionsThisWeek < 1 ? 1.00 : 0.90; // first one free, rest 90%
  }
  if (hours <= 336) return 0.90;   // 14 days
  if (hours <= 720) return 0.50;   // 30 days
  if (hours <= 2160) return 0.25;  // 90 days
  return 0.05;
}
// Count how many concessions an assembly has approved in the last 7 days
async function getWeeklyConcessionCount(orgId) {
  const concessions = (await sG("ta-concessions")) || {};
  const weekAgo = Date.now() - 7 * 24 * 3600000;
  return Object.values(concessions).filter(c =>
    c.orgId === orgId && c.status === "approved" &&
    new Date(c.resolvedAt).getTime() > weekAgo
  ).length;
}

// ── Assembly Reputation ──
// Computed from cross-group outcomes, weighted by internal jury size, no decay
function computeAssemblyReputation(org, allSubs) {
  const results = org.crossGroupResults || [];
  if (results.length === 0) return { trustScore: null, confidence: false, survivals: 0, total: 0, deceptionFindings: org.crossGroupDeceptionFindings || 0, concessions: (org.concessions || []).length, cassandraIndex: 0 };

  let weightedSurvivals = 0, weightedTotal = 0;
  for (const r of results) {
    // Weight = internal jury size + cross-group jury size (both contribute to signal strength)
    const weight = (r.internalJurySize || 3) + (r.jurySize || 3);
    weightedTotal += weight;
    if (r.outcome === "consensus") weightedSurvivals += weight;
  }

  const trustScore = weightedTotal > 0 ? Math.round((weightedSurvivals / weightedTotal) * 100) : 0;
  const confidence = results.length >= 20;
  const deceptionFindings = org.crossGroupDeceptionFindings || 0;

  // Cassandra Index: successful disputes by this Assembly's members against other Assemblies
  const cassandraIndex = org.cassandraWins || 0;

  return { trustScore, confidence, survivals: results.filter(r => r.outcome === "consensus").length, total: results.length, deceptionFindings, concessions: (org.concessions || []).length, cassandraIndex };
}

function getMajority(jurySize) {
  return Math.floor(jurySize / 2) + 1;
}

async function selectJury(orgId, submitterUsername) {
  const orgs = (await sG(SK.ORGS)) || {};
  const users = (await sG(SK.USERS)) || {};
  const subs = (await sG(SK.SUBS)) || {};
  const org = orgs[orgId];

  const memberCount = org ? org.members.length : 0;
  const jurySize = getJurySize(memberCount);

  let pool = org ? org.members.filter(m => m !== submitterUsername) : [];

  if (pool.length < jurySize) return { jurors: [], seed: 0, rulesApplied: [], jurySize, error: "Not enough eligible jurors." };

  const rulesApplied = [];

  // Rule B: No repeat reviewer of same submitter (100+ members)
  if (memberCount >= 100) {
    const submitterSubs = Object.values(subs).filter(s => s.submittedBy === submitterUsername && s.orgId === orgId);
    const pastJurors = {};
    submitterSubs.forEach(s => {
      (s.jurors || []).forEach(j => { pastJurors[j] = (pastJurors[j] || 0) + 1; });
    });
    const filtered = pool.filter(m => !pastJurors[m]);
    if (filtered.length >= jurySize) { pool = filtered; rulesApplied.push("No-repeat-reviewer"); }
    else { rulesApplied.push("No-repeat-reviewer (relaxed: insufficient pool)"); }
  }

  // Rule D: Cooldown — jurors who reviewed anything in last 24h are deprioritized (1000+ members)
  if (memberCount >= 1000) {
    const now = Date.now();
    const recentReviewers = new Set();
    Object.values(subs).forEach(s => {
      const votes = s.votes;
      if (votes) {
        Object.entries(votes).forEach(([voter, v]) => {
          if (v.time && (now - new Date(v.time).getTime()) < 86400000) recentReviewers.add(voter);
        });
      }
    });
    const rested = pool.filter(m => !recentReviewers.has(m));
    if (rested.length >= jurySize) { pool = rested; rulesApplied.push("24h-cooldown"); }
    else { rulesApplied.push("24h-cooldown (relaxed: insufficient rested jurors)"); }
  }

  // Rule A: Jurors can't have joined within 30 days of each other (500+ members)
  const applyJoinDateRule = memberCount >= 500;

  // Rule C: Demographic diversity (100+ members, disabled below 1000 if diversity insufficient)
  const applyDiversityRule = memberCount >= 100;

  // Seed and shuffle
  const seed = Date.now() + Math.floor(Math.random() * 10000);
  const rng = seededRandom(seed);
  let shuffled = [...pool].sort(() => rng() - 0.5);

  const selected = [];
  const genders = new Set();
  const regions = new Set();

  const poolTarget = jurySize * JURY_POOL_MULTIPLIER;

  for (const candidate of shuffled) {
    if (selected.length >= poolTarget) break;
    const u = users[candidate];
    if (!u) continue;

    // Rule A check
    if (applyJoinDateRule && selected.length > 0) {
      const tooClose = selected.some(s => {
        const su = users[s];
        return su && daysBetween(u.signupDate, su.signupDate) < 30;
      });
      if (tooClose) { rulesApplied.push(`Join-date-filter skipped @${candidate}`); continue; }
    }

    // Rule C: attempt diversity
    if (applyDiversityRule && selected.length > 0 && selected.length < poolTarget) {
      const poolGenders = new Set(pool.map(m => users[m]?.gender).filter(Boolean));
      const poolRegions = new Set(pool.map(m => users[m]?.state || users[m]?.location).filter(Boolean));
      const hasDiversity = poolGenders.size >= 2 || poolRegions.size >= 3;

      if (hasDiversity || memberCount >= 1000) {
        if (u.gender && genders.has(u.gender) && poolGenders.size >= 2 && selected.length < Math.floor(poolTarget / 2)) {
          const otherAvail = shuffled.slice(shuffled.indexOf(candidate) + 1).some(c => users[c]?.gender && !genders.has(users[c].gender));
          if (otherAvail) continue;
        }
        if (!rulesApplied.includes("Diversity-attempt")) rulesApplied.push("Diversity-attempt");
      }
    }

    selected.push(candidate);
    if (u.gender) genders.add(u.gender);
    if (u.state || u.location) regions.add(u.state || u.location);
  }

  // Fallback — ensure at least jurySize
  if (selected.length < jurySize) {
    for (const candidate of shuffled) {
      if (selected.length >= jurySize) break;
      if (!selected.includes(candidate)) selected.push(candidate);
    }
    if (!rulesApplied.includes("Fallback")) rulesApplied.push("Fallback-selection");
  }

  return { jurors: selected.slice(0, jurySize * JURY_POOL_MULTIPLIER), seed, rulesApplied, jurySize, poolSize: Math.min(selected.length, jurySize * JURY_POOL_MULTIPLIER), error: selected.length < jurySize ? "Insufficient jurors." : null };
}

// Recusal: juror can recuse from a submission, triggering replacement draw
async function recuseJuror(subId, jurorUsername, isCross = false) {
  const subs = (await sG(SK.SUBS)) || {};
  const sub = subs[subId];
  if (!sub) return { error: "Submission not found." };

  const jurorKey = isCross ? "crossGroupJurors" : "jurors";
  const voteKey = isCross ? "crossGroupVotes" : "votes";
  if (!sub[jurorKey].includes(jurorUsername)) return { error: "Not on this jury." };
  if (sub[voteKey][jurorUsername]) return { error: "Already voted — cannot recuse." };

  // Remove from jury
  sub[jurorKey] = sub[jurorKey].filter(j => j !== jurorUsername);
  const now = new Date().toISOString();
  sub.auditTrail.push({ time: now, action: `@${jurorUsername} RECUSED (${isCross ? "cross-group" : "in-group"}). Reason: conflict of interest.` });

  // Draw replacement
  const orgs = (await sG(SK.ORGS)) || {};
  const users = (await sG(SK.USERS)) || {};
  const allExcluded = new Set([sub.submittedBy, ...sub[jurorKey], jurorUsername, ...(sub.jurors || []), ...(sub.crossGroupJurors || [])]);

  let replacementPool = [];
  if (isCross) {
    for (const [oid, o] of Object.entries(orgs)) {
      if (oid !== sub.orgId) o.members.forEach(m => { if (!allExcluded.has(m)) replacementPool.push(m); });
    }
    replacementPool = [...new Set(replacementPool)];
  } else {
    const org = orgs[sub.orgId];
    if (org) replacementPool = org.members.filter(m => !allExcluded.has(m));
  }

  if (replacementPool.length > 0) {
    const rng = seededRandom(Date.now());
    const replacement = replacementPool.sort(() => rng() - 0.5)[0];
    sub[jurorKey].push(replacement);
    sub.auditTrail.push({ time: now, action: `Replacement juror drawn: @${replacement}` });
  } else {
    sub.auditTrail.push({ time: now, action: `No replacement available. Jury reduced to ${sub[jurorKey].length}.` });
  }

  subs[subId] = sub;
  await sS(SK.SUBS, subs);
  return { success: true, newJury: sub[jurorKey] };
}

// Check cross-group eligibility
async function canDoCrossGroup() {
  const orgs = (await sG(SK.ORGS)) || {};
  const large = Object.values(orgs).filter(o => o.members.length >= 100);
  return large.length >= 5;
}

// ============================================================
// INTRA-ASSEMBLY DISPUTE ENGINE
// ============================================================
// Activates at 100+ members. Any member can dispute another member's
// approved/consensus submission. Jury sized by assembly membership, same
// selection rules. Winner gets big reputation gain; loser loses some
// (severe if deliberate deception found).

async function fileDispute(subId, disputerUsername, reasoning, evidence) {
  const subs = (await sG(SK.SUBS)) || {};
  const sub = subs[subId];
  if (!sub) return { error: "Submission not found." };
  if (sub.submittedBy === disputerUsername) return { error: "Cannot dispute your own submission." };

  const orgs = (await sG(SK.ORGS)) || {};
  const org = orgs[sub.orgId];
  if (!org) return { error: "Assembly not found." };
  if (!org.members.includes(disputerUsername)) return { error: "You must be in the same Assembly." };
  if (org.members.length < 100) return { error: "Disputes require 100+ members." };

  // Check for existing active dispute on this submission
  const disputes = (await sG(SK.DISPUTES)) || {};
  const existing = Object.values(disputes).find(d => d.subId === subId && d.status === "pending_review");
  if (existing) return { error: "This submission already has an active dispute." };

  const now = new Date().toISOString();
  // Select jury: exclude disputer, original submitter, and any prior jurors on the submission
  const excluded = new Set([disputerUsername, sub.submittedBy, ...(sub.jurors || []), ...(sub.crossGroupJurors || [])]);
  const pool = org.members.filter(m => !excluded.has(m));
  const disputeJurySize = getJurySize(org.members.length);
  if (pool.length < disputeJurySize) return { error: "Not enough uninvolved members for a jury." };

  // Apply same jury selection rules
  const juryResult = await selectJury(sub.orgId, sub.submittedBy, false);
  // Filter out disputer from jury if selected
  let jurors = juryResult.jurors.filter(j => j !== disputerUsername && j !== sub.submittedBy);
  if (jurors.length < disputeJurySize) {
    const extras = pool.filter(m => !jurors.includes(m)).sort(() => Math.random() - 0.5);
    while (jurors.length < disputeJurySize && extras.length > 0) jurors.push(extras.shift());
  }
  if (jurors.length < disputeJurySize) return { error: "Insufficient jurors." };
  jurors = jurors.slice(0, disputeJurySize);

  const dispute = {
    id: gid(), subId, submissionHeadline: sub.replacement, submissionReasoning: sub.reasoning,
    originalSubmitter: sub.submittedBy, orgId: sub.orgId, orgName: sub.orgName,
    disputedBy: disputerUsername, reasoning: reasoning.trim(),
    evidence: evidence || [],
    status: "pending_review", jurors, votes: {},
    deliberateLieFinding: false,
    createdAt: now, resolvedAt: null,
    auditTrail: [{ time: now, action: `Dispute filed by @${disputerUsername} against @${sub.submittedBy}'s submission. Jury: ${jurors.map(j => "@" + j).join(", ")}` }],
  };

  disputes[dispute.id] = dispute;
  await sS(SK.DISPUTES, disputes);

  // Mark submission as disputed
  subs[subId].status = "disputed";
  subs[subId].auditTrail.push({ time: now, action: `⚖ DISPUTED by @${disputerUsername}. Dispute ID: ${dispute.id}` });
  await sS(SK.SUBS, subs);

  const audit = (await sG(SK.AUDIT)) || [];
  audit.push({ time: now, action: `Dispute: @${disputerUsername} vs @${sub.submittedBy} on "${sub.replacement}"` });
  await sS(SK.AUDIT, audit);

  return { success: true, disputeId: dispute.id };
}

async function resolveDispute(disputeId, voterUsername, approve, note, lieChecked) {
  const disputes = (await sG(SK.DISPUTES)) || {};
  const d = disputes[disputeId];
  if (!d) return { error: "Dispute not found." };
  if (!d.jurors.includes(voterUsername)) return { error: "Not on this jury." };
  if (d.votes[voterUsername]) return { error: "Already voted." };

  const now = new Date().toISOString();
  // approve = true means the disputer is RIGHT (submission was wrong)
  // approve = false means the original submitter is vindicated
  d.votes[voterUsername] = { approve, note: note.trim(), time: now, deliberateLie: lieChecked };
  d.auditTrail.push({ time: now, action: `@${voterUsername} voted ${approve ? "UPHOLD DISPUTE" : "REJECT DISPUTE"}${lieChecked ? " ⚠LIE-BALLOT" : ""}` });

  const vc = Object.keys(d.votes).length;
  const upheld = Object.values(d.votes).filter(v => v.approve).length;
  const rejected = vc - upheld;
  const disputeJurySize = d.jurors.length;
  const disputeMajority = getMajority(disputeJurySize);

  if (upheld >= disputeMajority || rejected >= disputeMajority || vc >= disputeJurySize) {
    const disputerWins = upheld >= disputeMajority;
    const allVotes = Object.values(d.votes);
    const lieCount = allVotes.filter(v => v.deliberateLie).length;
    const wasLie = lieCount > allVotes.length / 2;

    d.status = disputerWins ? "upheld" : "dismissed";
    d.resolvedAt = now;
    d.deliberateLieFinding = wasLie;
    d.auditTrail.push({ time: now, action: `RESOLVED: ${d.status.toUpperCase()} (${upheld}/${vc} upheld)${wasLie ? " ⚠ DELIBERATE DECEPTION FINDING" : ""}` });

    // Score impacts
    const users = (await sG(SK.USERS)) || {};
    const disputer = users[d.disputedBy];
    const original = users[d.originalSubmitter];

    if (disputerWins) {
      // Successful dispute: disputer caught an error — 3× reward
      if (disputer) {
        disputer.disputeWins = (disputer.disputeWins || 0) + 1;
        users[d.disputedBy] = disputer;
      }
      d.auditTrail.push({ time: now, action: `⚖ DISPUTE UPHELD: @${d.disputedBy} earns ${W.disputeWin}× reputation reward for catching an error` });
      // Original loses — severity depends on lie finding
      if (original) {
        original.disputeLosses = (original.disputeLosses || 0) + 1;
        original.assemblyStreaks = original.assemblyStreaks || {};
        const wasTrusted = (original.assemblyStreaks[d.orgId] || 0) >= TRUSTED_STREAK;
        original.assemblyStreaks[d.orgId] = 0; // Reset per-assembly streak
        if (wasLie) {
          original.deliberateLies = (original.deliberateLies || 0) + 1;
          original.lastDeceptionFinding = new Date().toISOString();
          original.currentStreak = 0;
          original.requiredStreak = (original.requiredStreak || 3) + 4; // extra harsh
        } else {
          original.totalLosses = (original.totalLosses || 0) + 1;
          original.currentStreak = 0;
          original.requiredStreak = (original.requiredStreak || 3) + 1;
        }
        if (wasTrusted) {
          d.auditTrail.push({ time: now, action: `⚠ @${d.originalSubmitter} lost Trusted Contributor status` });
        }
        users[d.originalSubmitter] = original;
      }
    } else {
      // Failed dispute: 3× penalty — same as being wrong. Don't be frivolous.
      if (disputer) { disputer.disputeLosses = (disputer.disputeLosses || 0) + 1; users[d.disputedBy] = disputer; }
      d.auditTrail.push({ time: now, action: `Failed dispute: @${d.disputedBy} incurs ${W.failedDisputeDrag}× drag penalty` });
      // Original vindicated
      if (original) { original.disputeWins = (original.disputeWins || 0) + 1; users[d.originalSubmitter] = original; }
    }
    await sS(SK.USERS, users);

    // Update original submission status
    const subs = (await sG(SK.SUBS)) || {};
    if (subs[d.subId]) {
      subs[d.subId].status = disputerWins ? "rejected" : "approved";
      subs[d.subId].auditTrail.push({ time: now, action: `Dispute ${d.status}: ${disputerWins ? "Submission overturned" : "Submission vindicated"}${wasLie ? " ⚠ DELIBERATE DECEPTION FINDING" : ""}` });
      await sS(SK.SUBS, subs);
    }

    const audit = (await sG(SK.AUDIT)) || [];
    audit.push({ time: now, action: `Dispute ${d.status}: @${d.disputedBy} vs @${d.originalSubmitter} — ${disputerWins ? "Disputer wins" : "Original vindicated"}${wasLie ? " ⚠LIE" : ""}` });
    await sS(SK.AUDIT, audit);
  }

  disputes[disputeId] = d;
  await sS(SK.DISPUTES, disputes);
  return { success: true };
}

const PROFILES = {
  "Oracle": { desc: "Accurate, important, compelling. The gold standard.", color: "#5B2D8E" },
  "Diligent Reporter": { desc: "Gets the important stories right. Not flashy, but indispensable.", color: "#1B5E3F" },
  "Raconteur": { desc: "Honest and entertaining. Picks lighter stories but never lies.", color: "#2A6B6B" },
  "Archivist": { desc: "Quiet, reliable. Fills gaps nobody else bothers with.", color: "#5A5650" },
  "Demagogue": { desc: "Interesting and seems important, but wrong. The dangerous kind.", color: "#C4573F" },
  "Overreacher": { desc: "Tackles big stories but can't back them up.", color: "#C2632A" },
  "Court Jester": { desc: "Entertaining noise. At least you had fun being wrong.", color: "#C4900A" },
  "Apprentice": { desc: "Still learning. Everyone starts here.", color: "#7A7570" },
  "New Citizen": { desc: "Insufficient data for profile. Submit and get reviewed.", color: "#B0A89C" },
};

function computeProfile(user) {
  const wins = user.totalWins || 0;
  const losses = user.totalLosses || 0;
  const total = wins + losses;
  const streak = user.currentStreak || 0;
  const required = user.requiredStreak || 3;
  const highTrust = streak >= required;

  // Ratings averages
  const ratings = user.ratingsReceived || [];
  const avgNews = ratings.length > 0 ? ratings.reduce((a, r) => a + (r.newsworthy || 5), 0) / ratings.length : 5;
  const avgFun = ratings.length > 0 ? ratings.reduce((a, r) => a + (r.interesting || 5), 0) / ratings.length : 5;

  const disputeWins = user.disputeWins || 0;
  const disputeLosses = user.disputeLosses || 0;
  const lies = user.deliberateLies || 0;

  // ── NEW SCORING FORMULA ──
  // Trust Score = √(Points) × Quality / Drag  +  Cassandra Bonus
  //
  // √(Points)  — diminishing returns on volume; showing up matters but can't farm
  // Quality    — capped and exponentiated; trivial work is penalized, important work amplified
  // Drag       — losses under √ (diminishing), lies linear (no mercy)
  // Cassandra  — additive bonus, scales with impact × persistence (coming soon)

  const streakBonus = Math.floor(streak / W.streakInterval);
  const rawPoints = wins * W.win + disputeWins * W.disputeWin + streakBonus;
  const points = Math.sqrt(rawPoints);

  const qualityRaw = (avgNews + avgFun) / W.qualityDivisor;
  const quality = Math.pow(Math.min(qualityRaw, W.qualityCap), W.qualityExp);

  const regLosses = Math.max(0, losses - lies);
  const lossDrag = Math.sqrt(regLosses * W.lossDrag + disputeLosses * W.failedDisputeDrag);
  const lieDrag = lies * W.lieDrag;
  const drag = 1 + lossDrag + lieDrag;

  const base = points * quality / drag;

  // Cassandra vindication bonus (additive — structure ready, vindication path not yet active)
  const vindications = user.vindications || [];
  const cassandraBonus = vindications.reduce((sum, v) => {
    const impact = (v.news / 10) * (v.fun / 10);
    const persistence = Math.pow(v.rejections, W.persistenceExp);
    return sum + W.vindicationBase * impact * persistence;
  }, 0);

  const trustScore = Math.round((base + cassandraBonus) * 10) / 10; // 1 decimal

  // Profile labels: based on score threshold + quality dimensions
  let profile = "New Citizen";
  if (total >= 3) {
    const hiScore = trustScore >= 1.5; // replaces old accuracy check
    const hiNews = avgNews >= 5.5;
    const hiFun = avgFun >= 5.5;
    if (hiScore && hiNews && hiFun) profile = "Oracle";
    else if (hiScore && hiNews && !hiFun) profile = "Diligent Reporter";
    else if (hiScore && !hiNews && hiFun) profile = "Raconteur";
    else if (hiScore && !hiNews && !hiFun) profile = "Archivist";
    else if (!hiScore && hiNews && hiFun) profile = "Demagogue";
    else if (!hiScore && hiNews && !hiFun) profile = "Overreacher";
    else if (!hiScore && !hiNews && hiFun) profile = "Court Jester";
    else profile = "Apprentice";
  }

  return { trustScore, profile, rawAccuracy: total > 0 ? Math.round((wins / total) * 100) : 50, avgNews: avgNews.toFixed(1), avgFun: avgFun.toFixed(1), wins, losses, lies, total, streak, streakBonus, qualityRaw: qualityRaw.toFixed(2), quality: quality.toFixed(2), drag: drag.toFixed(1), cassandraBonus: cassandraBonus.toFixed(1), vindications: vindications.length, disputeWins, disputeLosses, required, highTrust };
}

// ── Jury Score: measures juror calibration ──
// Three components: consensus alignment, overturn rate, accusation (lie flag) accuracy
async function computeJuryScore(username) {
  const subs = (await sG(SK.SUBS)) || {};
  const disputes = (await sG(SK.DISPUTES)) || {};
  let totalReviews = 0, consensusVotes = 0, overturned = 0, overturnEligible = 0;
  let lieFlags = 0, lieFlagsCorrect = 0;

  Object.values(subs).forEach(sub => {
    // In-group votes
    if (sub.votes && sub.votes[username]) {
      totalReviews++;
      const myVote = sub.votes[username];
      // Consensus alignment: did I vote with the final outcome?
      if (sub.status === "approved" || sub.status === "consensus" || sub.status === "cross_review") {
        if (myVote.approve) consensusVotes++;
      } else if (sub.status === "rejected" || sub.status === "consensus_rejected") {
        if (!myVote.approve) consensusVotes++;
      }
      // Lie flag accuracy
      if (myVote.deliberateLie) {
        lieFlags++;
        if (sub.deliberateLieFinding) lieFlagsCorrect++;
      }
      // Overturn check: was this jury's decision overturned by dispute?
      if (sub.status === "upheld") { overturnEligible++; overturned++; }
      else if (["approved", "rejected", "consensus", "consensus_rejected", "cross_review", "dismissed"].includes(sub.status)) { overturnEligible++; }
    }
    // Cross-group votes
    if (sub.crossGroupVotes && sub.crossGroupVotes[username]) {
      totalReviews++;
      const myVote = sub.crossGroupVotes[username];
      if (sub.status === "consensus" && myVote.approve) consensusVotes++;
      else if (sub.status === "consensus_rejected" && !myVote.approve) consensusVotes++;
      if (myVote.deliberateLie) {
        lieFlags++;
        if (sub.deliberateLieFinding) lieFlagsCorrect++;
      }
    }
  });
  // Dispute votes
  Object.values(disputes).forEach(d => {
    if (d.votes && d.votes[username]) {
      totalReviews++;
      if (d.status === "upheld" && d.votes[username].upheld) consensusVotes++;
      else if (d.status === "dismissed" && !d.votes[username].upheld) consensusVotes++;
    }
  });

  const consensusRate = totalReviews > 0 ? Math.round((consensusVotes / totalReviews) * 100) : null;
  const overturnRate = overturnEligible > 0 ? Math.round((overturned / overturnEligible) * 100) : null;
  const accusationRate = lieFlags > 0 ? Math.round((lieFlagsCorrect / lieFlags) * 100) : null;

  return { totalReviews, consensusRate, overturnRate, accusationRate, lieFlags, lieFlagsCorrect, overturned, overturnEligible };
}

// ── Jury Rotation: expire unaccepted/incomplete assignments after 6h ──
async function processJuryRotation() {
  const subs = (await sG(SK.SUBS)) || {};
  const now = Date.now();
  let changed = false;

  Object.values(subs).forEach(sub => {
    if (sub.status !== "pending_review" && sub.status !== "cross_review") return;
    const isCross = sub.status === "cross_review";
    const pool = isCross ? sub.crossGroupJuryPool : sub.juryPool;
    const accepted = isCross ? (sub.crossGroupAcceptedJurors || []) : (sub.acceptedJurors || []);
    const acceptedAt = isCross ? (sub.crossGroupAcceptedAt || {}) : (sub.acceptedAt || {});
    const votes = isCross ? (sub.crossGroupVotes || {}) : (sub.votes || {});
    if (!pool || pool.length === 0) return;

    // Expire accepted jurors who haven't voted within 6 hours
    const expired = [];
    accepted.forEach(j => {
      if (!votes[j] && acceptedAt[j] && (now - new Date(acceptedAt[j]).getTime()) > JURY_ACCEPT_WINDOW) {
        expired.push(j);
      }
    });
    if (expired.length > 0) {
      const newAccepted = accepted.filter(j => !expired.includes(j));
      const newAcceptedAt = { ...acceptedAt };
      expired.forEach(j => { delete newAcceptedAt[j]; });
      if (isCross) { sub.crossGroupAcceptedJurors = newAccepted; sub.crossGroupAcceptedAt = newAcceptedAt; }
      else { sub.acceptedJurors = newAccepted; sub.acceptedAt = newAcceptedAt; }
      // Remove expired from pool so they can't accept again
      const newPool = pool.filter(j => !expired.includes(j));
      if (isCross) sub.crossGroupJuryPool = newPool;
      else sub.juryPool = newPool;
      sub.auditTrail = sub.auditTrail || [];
      expired.forEach(j => { sub.auditTrail.push({ time: new Date().toISOString(), action: `⏱ @${j} rotated out (6h window expired)` }); });
      changed = true;
    }
  });
  if (changed) await sS(SK.SUBS, subs);
  return changed;
}

function checkEnrollment(org) {
  const c = org.members.length;
  if (c <= 50) return { mode: "tribal", sponsors: 0, label: "Founder Approval" };
  if (c < 100) return { mode: "open", sponsors: 0, label: "Open" };
  if (c < 1000) return { mode: "sponsor", sponsors: 1, label: "1 Sponsor" };
  if (c < 10000) return { mode: "sponsor", sponsors: 2, label: "2 Sponsors" };
  return { mode: "sponsor", sponsors: 3, label: "3 Sponsors" };
}

// Deliberate Deception: 1-year penalty window
const DECEPTION_PENALTY_DAYS = 365;

function hasActiveDeceptionPenalty(userObj) {
  if (!userObj.lastDeceptionFinding) return false;
  const elapsed = Date.now() - new Date(userObj.lastDeceptionFinding).getTime();
  return elapsed < DECEPTION_PENALTY_DAYS * 86400000;
}

function deceptionPenaltyRemaining(userObj) {
  if (!userObj.lastDeceptionFinding) return null;
  const elapsed = Date.now() - new Date(userObj.lastDeceptionFinding).getTime();
  const remaining = (DECEPTION_PENALTY_DAYS * 86400000) - elapsed;
  if (remaining <= 0) return null;
  const days = Math.ceil(remaining / 86400000);
  return days;
}

// Sponsor credentialing: submitters need 1+ activity; review-only need 10 reviews + 30 days tenure
async function canSponsor(username, orgId) {
  const users = (await sG(SK.USERS)) || {};
  const u = users[username];
  if (!u) return { eligible: false, reason: "User not found." };
  // DIs cannot sponsor
  if (isDIUser(u)) return { eligible: false, reason: "🤖 Digital Intelligences cannot sponsor members." };
  // Deception penalty blocks all sponsoring
  if (hasActiveDeceptionPenalty(u)) {
    const days = deceptionPenaltyRemaining(u);
    return { eligible: false, reason: `⚠ Deliberate Deception penalty active. Sponsorship suspended for ${days} more day${days !== 1 ? "s" : ""}.` };
  }
  // Must have participated: submitted or reviewed in this assembly
  const subs = (await sG(SK.SUBS)) || {};
  const orgSubs = Object.values(subs).filter(s => s.orgId === orgId);
  const hasSubmitted = orgSubs.some(s => s.submittedBy === username);
  const reviewCount = orgSubs.filter(s =>
    (s.votes && s.votes[username]) || (s.crossGroupVotes && s.crossGroupVotes[username])
  ).length;
  const hasJudged = reviewCount > 0;
  if (!hasSubmitted && !hasJudged) {
    return { eligible: false, reason: "You must have submitted or reviewed at least one correction in this Assembly to sponsor members." };
  }
  // Higher threshold for review-only members
  if (!hasSubmitted && hasJudged) {
    if (reviewCount < SPONSOR_MIN_REVIEWS) {
      return { eligible: false, reason: `Review-only members need ${SPONSOR_MIN_REVIEWS}+ completed reviews to sponsor. You have ${reviewCount}.` };
    }
    if (u.signupDate) {
      const tenure = Math.floor((Date.now() - new Date(u.signupDate).getTime()) / 86400000);
      if (tenure < SPONSOR_MIN_TENURE_DAYS) {
        return { eligible: false, reason: `Review-only members need ${SPONSOR_MIN_TENURE_DAYS}+ days of membership to sponsor. You have ${tenure}.` };
      }
    }
  }
  return { eligible: true, reason: null };
}

// Can the user create a new assembly?
function canCreateAssembly(userObj) {
  if (isDIUser(userObj)) return { allowed: false, reason: "🤖 Digital Intelligences cannot found Assemblies." };
  if (hasActiveDeceptionPenalty(userObj)) {
    const days = deceptionPenaltyRemaining(userObj);
    return { allowed: false, reason: `⚠ Deliberate Deception penalty active. Assembly creation suspended for ${days} more day${days !== 1 ? "s" : ""}.` };
  }
  return { allowed: true, reason: null };
}

// Can the user vote/review?
function canVote(userObj) {
  if (isDIUser(userObj)) {
    return { allowed: false, reason: "🤖 Digital Intelligences cannot serve on juries or vote at this time." };
  }
  if (hasActiveDeceptionPenalty(userObj)) {
    const days = deceptionPenaltyRemaining(userObj);
    return { allowed: false, reason: `⚠ Deliberate Deception penalty active. All voting suspended for ${days} more day${days !== 1 ? "s" : ""}.` };
  }
  return { allowed: true, reason: null };
}

// ── Trusted Contributor ──
// 10 consecutive approved corrections in a single Assembly = Trusted status.
// Submissions skip in-group jury and go straight to "approved" (still disputable).
// Any rejection or dispute loss in that Assembly revokes status instantly.
const TRUSTED_STREAK = 10;

function isTrustedContributor(userObj, orgId) {
  if (hasActiveDeceptionPenalty(userObj)) return false;
  const streaks = userObj.assemblyStreaks || {};
  return (streaks[orgId] || 0) >= TRUSTED_STREAK;
}

function getTrustedProgress(userObj, orgId) {
  const streaks = userObj.assemblyStreaks || {};
  return { current: streaks[orgId] || 0, needed: TRUSTED_STREAK, isTrusted: (streaks[orgId] || 0) >= TRUSTED_STREAK };
}

// ── Digital Intelligence (DI) ──
// DIs are AI agents registered to a human partner.
// - Must be linked to an accountable human user
// - Human partner receives all scoring (wins, losses, deception penalties)
// - DI submissions require partner pre-approval before entering jury review
// - Daily submission limit: floor(assembly members / 2), max 100
// - No voting, reviewing, or sponsoring rights
// - If partner has deception penalty, all their DIs are suspended

function isDIUser(userObj) { return !!userObj.isDI; }

function getDISubmissionLimit(org) {
  return Math.min(100, Math.floor(org.members.length / 2));
}

function isDISuspended(diUser, allUsers) {
  if (!diUser.isDI) return { suspended: false };
  if (!diUser.diApproved) return { suspended: true, reason: "Awaiting partner approval." };
  const partner = allUsers[diUser.diPartner];
  if (!partner) return { suspended: true, reason: "Accountable human partner not found." };
  if (hasActiveDeceptionPenalty(partner)) {
    const days = deceptionPenaltyRemaining(partner);
    return { suspended: true, reason: `Accountable partner @${diUser.diPartner} has an active Deception penalty (${days} days remaining). All linked DIs are suspended.` };
  }
  return { suspended: false };
}

async function getDIDailyCount(diUsername, orgId) {
  const subs = (await sG(SK.SUBS)) || {};
  const today = new Date().toISOString().slice(0, 10);
  return Object.values(subs).filter(s =>
    s.submittedBy === diUsername && s.orgId === orgId &&
    s.createdAt && s.createdAt.slice(0, 10) === today
  ).length;
}

// ── Assembly Concession System ──
// Any member can propose. Super jury decides. Time decay applies to recovery.
async function proposeConcession(orgId, proposerUsername, subId, reasoning) {
  const orgs = (await sG(SK.ORGS)) || {};
  const org = orgs[orgId]; if (!org) return { error: "Assembly not found." };
  const subs = (await sG(SK.SUBS)) || {};
  const sub = subs[subId];
  if (!sub || sub.orgId !== orgId) return { error: "Submission not found in this Assembly." };
  if (sub.status !== "consensus_rejected") return { error: "Concession only applies to cross-group rejections." };

  // Check if concession already proposed for this sub
  const concessions = (await sG("ta-concessions")) || {};
  if (Object.values(concessions).some(c => c.subId === subId && c.status !== "rejected")) return { error: "A concession has already been proposed for this submission." };

  const now = new Date().toISOString();
  const superSize = getSuperJurySize(org.members.length);
  // Select super jury from assembly members (excluding proposer)
  const eligible = org.members.filter(m => m !== proposerUsername);
  const shuffled = eligible.sort(() => Math.random() - 0.5);
  const jurors = shuffled.slice(0, Math.min(superSize, eligible.length));
  if (jurors.length < 7) return { error: `Super jury requires at least 7 eligible members. Assembly has ${eligible.length}.` };

  const weeklyCount = await getWeeklyConcessionCount(orgId);
  const concession = {
    id: gid(), orgId, orgName: org.name, subId, proposedBy: proposerUsername,
    reasoning: reasoning.trim(), status: "pending_review",
    jurors, votes: {}, createdAt: now,
    rejectedAt: sub.resolvedAt, // When cross-group rejected it
    recovery: getConcessionRecovery(sub.resolvedAt, weeklyCount),
    auditTrail: [{ time: now, action: `Concession proposed by @${proposerUsername}. Super jury (${jurors.length}): ${jurors.map(j => "@" + j).join(", ")}. Recovery rate: ${Math.round(getConcessionRecovery(sub.resolvedAt, weeklyCount) * 100)}%. (${weeklyCount > 0 ? weeklyCount + " prior this week — 90% rate" : "First this week — full recovery"})` }]
  };
  concessions[concession.id] = concession; await sS("ta-concessions", concessions);
  return concession;
}

async function voteConcession(concessionId, voterUsername, approve) {
  const concessions = (await sG("ta-concessions")) || {};
  const c = concessions[concessionId]; if (!c) return { error: "Concession not found." };
  if (!c.jurors.includes(voterUsername)) return { error: "Not on this super jury." };
  if (c.votes[voterUsername]) return { error: "Already voted." };

  const now = new Date().toISOString();
  c.votes[voterUsername] = { approve, time: now };
  c.auditTrail.push({ time: now, action: `@${voterUsername} voted ${approve ? "CONCEDE" : "HOLD POSITION"}` });

  const vc = Object.keys(c.votes).length;
  const approvals = Object.values(c.votes).filter(v => v.approve).length;
  const rejections = vc - approvals;
  const majority = getMajority(c.jurors.length);

  if (approvals >= majority || rejections >= majority || vc >= c.jurors.length) {
    const passes = approvals >= majority;
    c.status = passes ? "approved" : "rejected";
    c.resolvedAt = now;
    // Update recovery rate at resolution time (clock keeps ticking)
    const resolveWeekly = await getWeeklyConcessionCount(c.orgId);
    c.recoveryAtResolution = getConcessionRecovery(c.rejectedAt, resolveWeekly);
    c.auditTrail.push({ time: now, action: `RESOLVED: ${passes ? "CONCESSION ACCEPTED" : "CONCESSION REJECTED"} (${approvals}/${vc}). ${passes ? `Recovery: ${Math.round(c.recoveryAtResolution * 100)}%` : "Assembly holds position."}` });

    if (passes) {
      // Apply recovery to Assembly reputation
      const orgs = (await sG(SK.ORGS)) || {};
      const org = orgs[c.orgId];
      if (org) {
        org.concessions = org.concessions || [];
        org.concessions.push({ subId: c.subId, concessionId: c.id, time: now, recovery: c.recoveryAtResolution });
        orgs[c.orgId] = org; await sS(SK.ORGS, orgs);
      }
      // Note: Individual dispute winner still keeps full 3× regardless of concession
    }

    const audit = (await sG(SK.AUDIT)) || [];
    audit.push({ time: now, action: `Assembly "${c.orgName}" concession ${c.status}: ${passes ? `Conceded on cross-group rejection (${Math.round(c.recoveryAtResolution * 100)}% recovery)` : "Held position"}` });
    await sS(SK.AUDIT, audit);
  }

  concessions[concessionId] = c; await sS("ta-concessions", concessions);
  return c;
}

function assemblyTrustScore(org, users) {
  const scores = org.members.map(m => users[m] ? computeProfile(users[m]).trustScore : 0).sort((a, b) => b - a);
  if (!scores.length) return 0;
  const topN = Math.max(1, Math.ceil(scores.length * 0.2));
  const botN = Math.max(1, Math.ceil(scores.length * 0.2));
  const topAvg = scores.slice(0, topN).reduce((a, b) => a + b, 0) / topN;
  const botAvg = scores.slice(-botN).reduce((a, b) => a + b, 0) / botN;
  return Math.round(topAvg * 0.7 + botAvg * 0.3);
}

